var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>코핀 컴퍼니 부사장 이수연입니다.</color>","JPN":"<color=#ffd34c>コフィンカンパニー副社長のカナミ・キズナです。</color>","ENG":"<color=#ffd34c>You've reached Vice President Lee Sooyeon of Coffin Company.</color>","TWN":"<color=#ffd34c>我是科芬公司副總 李秀妍。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>지금은 연락을 받을 수 없으니 음성 메시지를 남겨 주십시오.</color>","JPN":"<color=#ffd34c>只今不在にしておりますので、発信音の後にお名前とご用件をお話しください。</color>","ENG":"<color=#ffd34c>I am unable to come to the phone right now. Please leave a message.</color>","TWN":"<color=#ffd34c>現在無法通話，請留下語音訊息。</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"윌버에 대한 정보를 언제 수령할 수 있을지 알고 싶습니다. 휴먼.","JPN":"ウィルバーに関する情報をいつもらえるか知りたいです、ヒューマン。","ENG":"I'd like to know if you have any updates on Wilbur. Human.","TWN":"人類，我想知道什麼時候可以收到韋爾伯的資訊。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이번이 13,740,266회째 수신 미확인된 메시지로 남지 않길 바랍니다.","JPN":"今回が13,740,266回目の受信未確認メッセージとして残らないことを祈ります。","ENG":"I hope this won't be just the 13,740,266th unchecked message.","TWN":"希望這不是第13,740,266次未回覆的訊息。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"30초 후 다시 연락드리겠습니다. 이상.","JPN":"30秒後にまたご連絡いたします、以上。","ENG":"I'll contact you again in 30 seconds. Over and out.","TWN":"30秒後我會再打來，以上。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"미안합니다. 대시, 리타.","JPN":"ごめんなさい。ダッシュ、リタ。","ENG":"I'm sorry, Dash and Rita.","TWN":"抱歉，黛西、麗塔。"},"stage":{"bg":"HORIZON_01_B","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"이면세계를 수색하는 동안 제 정보망이 상당 부분 훼손되었더군요.","JPN":"裏世界を捜索する間に、私の情報網の相当部分が破損してしまいました。","ENG":"Searching the Counterside had significantly damaged my information network.","TWN":"搜查異界的時候，我的情報網有部分毀損。"},"stage":{"bg":"HORIZON_01_B","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"윌버의 행방을 알아내기 위해서는……. 지원이 필요합니다.","JPN":"ウィルバーの行方を突き止めるためには……サポートが必要です。","ENG":"In order to locate Wilbur… I will need help.","TWN":"要想找到韋爾伯的下落……就需要支援。"},"stage":{"bg":"HORIZON_01_B","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"확실히 혼자로 돌아오니 예전처럼 일이 풀리지 않는군요.","JPN":"一人になってからは、前のようにうまくいきませんね。","ENG":"Things certainly haven't been as easy as they were now that I'm alone again.","TWN":"確實是就算一個人回到這裡，也無法像以前一樣解決事情"},"stage":{"bg":"HORIZON_01_B","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그러니 가능하다면 돌아와 주십시오. 월급을 200% 인상해 드리겠습니다.","JPN":"だから可能でしたら帰ってきてください。給料を200％引き上げます。","ENG":"So please come back, if it's at all possible. I will double your salaries.","TWN":"可以的話，請你們回來吧。我可以幫你們加薪200%。"},"stage":{"bg":"HORIZON_01_B","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……불가능하겠지만요.","JPN":"……不可能だとは思いますが。","ENG":"…Though I doubt that is possible.","TWN":"……根本不可能吧。"},"stage":{"bg":"HORIZON_01_B","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>주간고속도로 제 5호선 상의 폭발음 감지.</color>","JPN":"<color=#ffd34c>州間高速道路第5号線から爆発音を感知。</color>","ENG":"<color=#ffd34c>Explosion detected on the 5th Interstate Highway.</color>","TWN":"<color=#ffd34c>感應到州間高速公路5號線上的爆炸聲響。</color>"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>샘플 분석 결과, 교전 발생 가능성 높음.</color>","JPN":"<color=#ffd34c>サンプル分析の結果、交戦発生の可能性大。</color>","ENG":"<color=#ffd34c>Sample analysis suggest engagement is highly likely.</color>","TWN":"<color=#ffd34c>樣本分析結果，發生衝突的可能性很高。</color>"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"내일 엠마 데려다 줄 때 같이 가겠다고 해. 그렇게 말하면 저래도 하룻밤은 재워 줄 거야.","JPN":"明日エマを病院に連れて行く時、一緒に行きたいって言って。そう言えば最低でも一晩は泊めてくれると思う。","ENG":"Tell him you'd like to tag along when we take Emma to the hospital tomorrow. If you do that, he'll let you stay, at least for the night.","TWN":"說你明天也想一起送愛瑪去醫院！院長聽到你那麼說，起碼會收留你一晚吧！"},"stage":{"bg":"BACKSTREET2","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……소음 공해가 너무 심하군요.","JPN":"……騒音公害がひどいですね。","ENG":"…There is far too much noise.","TWN":"……噪音汙染有點嚴重呢。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"직접 찾아가서 설득을 시도해야겠습니다.","JPN":"直接訪ねて説得しなければなりません。","ENG":"I'll have to try some in-person persuasion.","TWN":"還是親自去一趟來說服對方吧。"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>잔여 동력 9.7퍼센트.</color>","JPN":"<color=#ffd34c>残余エネルギー9.7％。</color>","ENG":"<color=#ffd34c>9.7% power remaining.</color>","TWN":"<color=#ffd34c>剩餘動能9.7%。</color>"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>비상 기동을 시행합니다.</color>","JPN":"<color=#ffd34c>非常起動を行います。</color>","ENG":"<color=#ffd34c>Initiating emergency maneuvers.</color>","TWN":"<color=#ffd34c>執行緊急啟動。</color>"},"stage":{"bg":"OFFICE_DETECT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"위대한 예언자 마젤란께서 감옥에 있던 내게 계시를 내리셨다!","JPN":"偉大なる預言者マジェラン様が、刑務所にいた私に啓示を授けてくださった！","ENG":"The Great Prophet Magellan bestowed a revelation upon me in prison!","TWN":"偉大的預言家 麥哲倫啟示在獄中的我！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"그분께서 못 이루신 과업을 대신하라고!","JPN":"あの方が果たせなかった偉業を代わりに成し遂げなさいと！","ENG":"He said I must complete his unfinished task!","TWN":"要我完成他未完成的偉業！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"가라, 마젤란의 형제들이여! 저들에게 우리를 방해한 죗값을 가르쳐 줘라!","JPN":"行け、マジェランの兄弟たちよ！　彼らに我々の邪魔をした罪を償わせてやれ！","ENG":"Go, ye brothers of Magellan! Teach them the price of getting in our way!","TWN":"走吧，麥哲倫的弟兄們！讓那些妨礙我們的人付出應有的代價！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"저 카운터가 문제입니다. 조준을 하고 사격해도 공격이 제대로 먹히질 않아요.","JPN":"問題はあのカウンターです。ちゃんと照準を合わせて撃っても攻撃があたりません。","ENG":"That Counter's a pain in the neck. We can't seem to land any attacks even if we take aimed shots.","TWN":"問題就是那個制裁者，就算瞄準他發射也打不中他。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그래. 공기 조작 능력이다. 하필이면 저 녀석이군.","JPN":"ああ、空気操作能力だ。よりによってあいつがな。","ENG":"I see. He's manipulating the air around him. And it had to be that guy, of all people…","TWN":"嗯嗯，是控制空氣的能力。怎麼偏偏是他！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아는 사람이야, 민우 아저씨? 그럼 말로 좀 하자고 해!","JPN":"マツダおじさんの知り合い？　じゃあ、話し合いで何とかならないんですか？","ENG":"You know him, Mr. Minwoo? Can you tell him to chill out?!","TWN":"是民宇叔叔認識的人嗎？那你跟他談談嘛！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L48_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"그러기에는 서면으로만 본 사이라서.","JPN":"知り合いではなく、書面でしか見たことないんでね。","ENG":"Unfortunately, we only met in writing.","TWN":"我只有在文件上看過他。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L49_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"저 녀석은 엘카노. 마젤란 예언회가 소탕될 때 수감되었다가 대규모 탈옥 사태 때 풀려난 카운터 범죄자다.","JPN":"あいつはエルカノ。マジェラン預言会が掃討された時に収監されたが、大規模脱獄事件の時に逃げたカウンター犯罪者だ。","ENG":"That right there is Elcano. He's a Counter Criminal who was incarcerated when the MPS was taken down. He broke out during the big jailbreak.","TWN":"那傢伙叫埃爾卡諾，在肅清麥哲倫預言會時曾被抓入獄，後來在大規模越獄事件時越獄成功的制裁者罪犯。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L50_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"카운터? 그러면 우리 큰일난 거 아냐?","JPN":"カウンター？　結構まずい状況ですよね？","ENG":"Counter? Then are we screwed?","TWN":"制裁者？那我們不就完蛋了？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"손짓으로 돌풍을 일으키는 인간을 어떻게 죽여?!","JPN":"手から突風を巻き起こす人をどうやって倒すの！？","ENG":"How are we supposed to kill someone who can create whirlwinds with a flick of his hand?!","TWN":"他隨便大手一揮就能掀起颶風，我們怎麼打得過他啦？！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L2_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"준비를 갖추지 않았으니 네 말처럼 죽이기엔 무리지.","JPN":"準備ができていないから、あんたの言うとおり殺すのは無理だ。","ENG":"We can't. Not without the proper preparation.","TWN":"你說的沒錯，沒準備好的話，要殺掉他根本是天方夜譚。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"하지만 여기서 살아나갈 방법은 아직 남아 있다.","JPN":"だが、ここで生き残る方法はまだ残っている。","ENG":"But that doesn't mean we can't make it out of here alive.","TWN":"但還有一個能活命的辦法！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"레이첼, 너는 엠마를 챙겨. 우린 우회해서 저 자식에게 한 방 먹여 줄 거다.","JPN":"レイチェル、エマを頼む。俺たちは回り込んであいつに一発食らわせる。","ENG":"Rachel, you grab Emma. The rest of us will flank that bastard and teach him a lesson.","TWN":"瑞秋，照顧愛瑪。我們繞過去給他一擊。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L6_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"호위하는 부하들이 있습니다. 가능할까요?","JPN":"護衛する部下たちがいます。いけそうですか？","ENG":"But he's got guards around him. Think it'll work?","TWN":"可是他旁邊有人守著，沒問題嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"해 봐야지. 손 놓고 저 놈들 제물로 바쳐지는 것보단 나을 거다.","JPN":"やってみないとな。何もせずにあいつらの生贄になるよりはマシだろう。","ENG":"We'll have to try. It'll be better than letting them get after us like this.","TWN":"試試看囉！與其直接去送死，不如放手一搏！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"으으, 이게 대체 무슨 꼴이야……!","JPN":"うう、いったい何なの……！","ENG":"Argh… How did things get this bad?!","TWN":"嗚嗚，會不會太狼狽……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GIRL_NPC_HORIZON_NULL","text":{"KOREA":"언니…… 괜찮아……?","JPN":"お姉ちゃん……大丈夫……？","ENG":"Rachel… Are you okay?","TWN":"姊姊……還好嗎……？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"무, 물론이지. 여긴 위험하니까 내가 안전한 데로 데려가 줄게.","JPN":"も、もちろん。ここは危ないから安全な場所に連れていくね。","ENG":"O-of course. Let me take you somewhere safe. This place is getting dangerous.","TWN":"沒…沒事！這裡很危險，姊姊帶你到安全的地方。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"영차……!","JPN":"よっこらしょ……！","ENG":"Heave-ho!","TWN":"嘿咻……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L19_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"응?","JPN":"うん？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"저길 봐! 우릴 기만했던 사악한 계집애다!","JPN":"あそこを見ろ！　俺たちをたらし込もうとした邪悪な女だ！","ENG":"Look! It's that evil chick who tricked us!","TWN":"你們看！那不是耍我們的那個壞丫頭嗎！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"오오, 마젤란이시여! 우리의 실수를 만회할 기회를 주시다니!","JPN":"ああ、マジェラン様！　我々に過ちを挽回する機会をくださるとは！","ENG":"Praised be Magellan! He's given us a chance to fix our mistake!","TWN":"喔～偉大的麥哲倫～竟然賜給我們挽回錯誤的機會！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐야, 저 자식들?! 여기까지 따라나온 거였어?!","JPN":"なんだよ、あいつら！？　ここまでついて来たの！？","ENG":"What the?! Did they follow me all the way out here?!","TWN":"那些傢伙是怎樣？！從剛剛就一直跟著我們嗎？！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"GIRL_NPC_HORIZON_NULL","text":{"KOREA":"어, 언니……! 나 무서워……!","JPN":"お、お姉ちゃん……怖いよ……！","ENG":"R-Rachel…! I'm scared!","TWN":"姊…姊姊…我好怕……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"눈 감아, 엠마! 언니가 지켜 줄게!","JPN":"目を閉じていてね、エマ！　お姉ちゃんが守ってあげるから！","ENG":"Close your eyes, Emma! I'll keep you safe!","TWN":"愛瑪，你把眼睛閉起來！姊姊會保護你的！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"GIRL_NPC_HORIZON_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"흐흐, 그래? 자기가 뭐 촌구석에 처박혀 살던 거물 카운터라도 되나 보지?","JPN":"ほう、できるのか？\\n実は一般人のフリして田舎に身を潜めていた大物カウンターでしたみたいな？　そりゃあ怖いな。","ENG":"Bwahaha, will you now? You some kind of big shot Counter who's been hiding away in the countryside?","TWN":"呵呵～是嗎？你以為你是困在鄉下的超級制裁者嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"설령 그렇더라도 우리의 축성 받은 대전차 로켓은 막을 수 없으리니!","JPN":"だとしても、我々の聖別された対戦車ロケット弾は止められないぞ！","ENG":"Even if that were the case, you don't stand a chance against our blessed RPG!","TWN":"就算是，也擋不住我們的反坦克炮的！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"뭐, 뭐야? 멀쩡하네?","JPN":"な、なに？　生きてる？","ENG":"W-what the? I'm… fine?","TWN":"嗯…？我沒事？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"설마 이거…….","JPN":"まさかこれ……","ENG":"Could this be what I think it is?","TWN":"難道……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"위기의 순간에 카운터 워치를 얻는 전개?!","JPN":"大ピンチの時にカウンターウォッチをゲットする展開！？","ENG":"Did I just get a Counter Watch in the moment of crisis?!","TWN":"我是在危機時就會獲得制裁者能量環的天才？！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"자아도취에서 깨어나시죠, 휴먼.","JPN":"夢から覚めましょう、ヒューマン。","ENG":"Don't let this get to your head, human.","TWN":"人類，你真是自我感覺良好。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"당신에게 올 만큼 카운터 워치도 넉넉하진 않을 겁니다.","JPN":"あなたの元にやってくるほど、カウンターウォッチはありふれたものではないので。","ENG":"I bet there aren't enough Counter Watches for one to just fall into your possession.","TWN":"就算是，那個制裁者能量環應該效果也不大。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"…………어?","JPN":"……あれ？","ENG":"…Huh?","TWN":"…………嗯？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"호라이즌! 여긴 어떻게 온 거야?!","JPN":"ホライズン！　どうしてここに？","ENG":"Horizon! How did you get here?","TWN":"地平線！你怎麼會來這裡？！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"소음 공해에 항의하러 뛰어 왔습니다.","JPN":"騒音公害に対して抗議しに来ました。","ENG":"I ran here to complain about the noise.","TWN":"我是跑來抗議噪音污染的。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"야! 그게 말이 돼?! 여기서 4번가까지 차로 몇십 분이 걸리는데!","JPN":"そんなことあり得るの！？　ここから4番街まで車でも数十分はかかるのに！","ENG":"What? That's ridiculous! It took almost an hour to get here from 4th Avenue! By car!","TWN":"拜託！怎麼可能？！從這裡到第四大道，就算搭車也要幾十分鐘欸！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"잠깐, 로켓탄은? 아까 저 인간들이 쏘지 않았어?","JPN":"ちょっと待って、ロケット弾は？　さっきあの人たちが撃ったのは？","ENG":"Hang on, where did the rocket go? Didn't those jerks shoot one just now?","TWN":"等等，砲彈呢？他們剛才不是有發射砲彈嗎？"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"궤도가 꺾여서 엉뚱한 곳으로 날아갔습니다. 불량품이었나 보죠.","JPN":"弾道が曲がって違う場所に飛んで行きました。不良品だったようです。","ENG":"It swerved its trajectory and flew elsewhere. It must have been a defective round.","TWN":"彎曲彈道後，砲彈就不知道飛哪去，感覺是瑕疵品。"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HERETIC_NPC_NULL_C","text":{"KOREA":"이런 멍청한 놈! 로켓탄 조준을 그렇게 하면 어떡해!","JPN":"このバカ野郎！　ロケット弾の照準をミスってどうするんだよ！","ENG":"You fool! What kind of aim was that?!","TWN":"你這個蠢蛋！是會不會瞄準！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HERETIC_NPC_NULL_D","text":{"KOREA":"너야말로 뭘 본 거야! 저 똘마니처럼 입은 여자애가 나타나자마자 궤도가 휘었다고!","JPN":"お前こそ何を見てたんだよ！　あの変な格好の小娘が現れたら弾道が曲がったんだよ！","ENG":"You're the fool here! The trajectory changed as soon as that thug girl appeared!","TWN":"你才是眼睛到底在看什麼！那個穿得像不良少女的女生一出現，彈道就彎曲了好嗎！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HERETIC_NPC_NULL_C","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HERETIC_NPC_NULL_D","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"주교님! 저들의 저항이 거셉니다!","JPN":"司教様！　奴らの抵抗が激しいです！","ENG":"Your Holiness! The enemy's resisting fiercely!","TWN":"主教！他們很頑強抵抗！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"부디 예언자께서 내리신 권능으로 저들을 무찔러 주소서!","JPN":"どうか預言者から授かった権能で彼らを打ち破ってください！","ENG":"Please vanquish them with the power bestowed upon you by the Prophet!","TWN":"請您使用預言家給您的能力，把他們全都滅掉！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"멍청한 놈들…… 용병도 아닌 저런 버러지들 상대로 쩔쩔 매다니.","JPN":"間抜けなやつらめ……傭兵でもないあんな虫けらどもを相手に手こずるとは。","ENG":"Fools… You can't even handle a bunch of amateurs? They're not even mercenaries!","TWN":"沒用的東西……他們又不是傭兵，不過是一群蟲子你們也束手無策！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"내가 저들을 직접 징벌하겠다! 다들 물러서라!","JPN":"この私が彼らを直接断罪する！　退け！","ENG":"Very well! I shall bring retribution upon them myself! Stand back!","TWN":"我親自出手來懲罰他們吧！都給我退下！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"글쎄, 내가 아무리 관대해도 그 꼴은 못 봐 주겠군.","JPN":"ふむ、俺がいくら寛大とはいえ、それは黙って見てられないな。","ENG":"Not on my watch, buddy.","TWN":"好吧，就算我脾氣再怎麼好，也實在是忍無可忍！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"커헉, 크하아악……!","JPN":"ぐはっ、ぐああああ……！","ENG":"Ack… Graah!","TWN":"唔，唉唷……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_COMBAT_MONSTER_HIT_BIG"},{"id":"L11_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"주교님!!","JPN":"司教様！！","ENG":"Bishop!","TWN":"主教！！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ANDRO_EXTRA_NULL_NULL","text":{"KOREA":"이, 이건 크레모아……? 수류탄도 못 구할 놈들이 이런 물건을 어디서……!","JPN":"こ、これはクレイモア……？　手榴弾すら持ってなさそうな奴らがこんな物をどこで……！","ENG":"I-is this… a claymore? Where did you petty fools get something like this?!","TWN":"這…這是闊刀地雷……？連手榴彈都弄不到的傢伙，是從哪弄來這種東西……！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ANDRO_EXTRA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"주, 주교님께서 부상을 입으셨다!","JPN":"し、司教様が負傷した！","ENG":"T-the Bishop is wounded!","TWN":"主…主教！您受傷了！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"HERETIC_NPC_NULL_A","text":{"KOREA":"다들 싸움을 멈춰라! 주교님을 모시고 어서 도망쳐야 해!","JPN":"戦闘中止！　司教様を連れて早く逃げるぞ！","ENG":"Everyone, disengage! We have to get the Bishop out of here at once!","TWN":"大家暫停！快掩護主教離開！"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"BATTLE_VIRTUAL","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HERETIC_NPC_NULL_A","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"우, 우리…… 죽다 살아난 거 맞지?","JPN":"ア、アタシたち……生き延びたんだよね？","ENG":"S-so… Did we actually win?","TWN":"我們……剛剛是九死一生對吧？ "},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CITY_STREET_DISASTER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L24_1","type":"dialog","speaker":null,"text":{"KOREA":"아, 이런. 장갑차 한 대는 완전히 뻗었어. 이거 폐차장에 끌고 가기도 무안할 정도네.","JPN":"まいったな。装甲車一台がズタボロになっちまった。\\nこりゃ廃車場に持って行くのも申し訳ないレベルだな。","ENG":"Oh, dang. This APC is completely kaput. I don't think even a junkyard would accept a mess like this.","TWN":"可惡，有台裝甲車完全慘不忍睹，連拖去廢車場都覺得丟臉。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":null,"text":{"KOREA":"그래도 덕분에 목숨은 건졌잖아. 낡아빠진 중고라도 돈 값은 해 준다 이거지.","JPN":"おかげで命だけは助かったじゃないか。ボロボロの中古車でも本来の役目は果たしてくれたのさ。","ENG":"At least it saved our lives. Even an old secondhand piece of crap like this is worth every penny.","TWN":"多虧有它才能保住我們的小命，就算是破爛的中古車還是有它的價值的。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":null,"text":{"KOREA":"이봐! 여기 이 녀석은 수리해서 굴릴 수 있겠어!","JPN":"おい、こいつは修理したら使えそうだ！","ENG":"Hey! I think we can get this one fixed up and working again!","TWN":"你們看！這傢伙修一修還是能動的啦！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"레이첼, 호라이즌을 데리고 이만 돌아가.","JPN":"レイチェル、ホライズンを連れて帰れ。","ENG":"Rachel, take Horizon and get out of here.","TWN":"瑞秋，你帶地平線回去。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"네?! 왜요?! 같이 가도 되잖아요! 엠마한테는 제가 필요하다고요!","JPN":"え？　なんで！？　一緒に行ってもいいでしょ？　エマにはアタシが必要です！","ENG":"What? Why?! Can't I tag along? Emma needs me!","TWN":"為什麼？！我們也要一起去！愛瑪需要我！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L32_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"예언회에서 노린다는 게 사실로 드러난 이상, 아무리 떼를 써도 그 부탁은 못 들어 줘.","JPN":"預言会が狙っているのが明確になった以上、駄々をこねられてもダメなものはダメだ。","ENG":"Now that we know the MPS is after us, no tantrum you can throw will change my mind.","TWN":"現在已經確定預言會有動作，不管你怎麼耍賴，我也不能帶你們去。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그렇지만…… 쟤 혼자 병원에 가면 무슨 푸대접을 받을지 모르는데……","JPN":"でも……あの子一人で病院に行って理不尽なことでもされたら……","ENG":"But… They might treat her like crap if she goes to the hospital alone…","TWN":"可是……我怕沒有我在身邊，愛瑪沒辦法受到好的照顧……"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"그건 걱정하지 마. 우리가 잘 얘기할 테니까.","JPN":"それは心配するな。俺たちがちゃんと話しておく。","ENG":"Don't you worry about that. We'll make sure they take good care of her.","TWN":"這一點你大可放心，我們會交代好的。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"우리끼리 거지라고 놀려도 남들이 그러면 다 같이 받아 쳐 주는 게 난민지구잖아.","JPN":"お互いを乞食だとバカにしても、外のやつからバカにされたら一丸となって戦うのが難民地区だろ。","ENG":"We might call each other names for being dirt poor, but we band together when outsiders try to mess with us. That's how the refugee district rolls.","TWN":"雖然平時會互開玩笑，但遇到事情的時候，總是一起面對，這就是難民區不是嗎？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"으, 이 오빠는 또 쪽팔리는 소리 하네.","JPN":"げっ、またこっぱずかしいこと言っちゃって。","ENG":"Ugh, spare me the cheesy crap.","TWN":"噁～這位大哥還真敢講！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"어쭈, 너 많이 컸다? 네 허풍 다 받아 주던 사람한테 못 하는 소리가 없어?","JPN":"おいおい、お前も最近どんどん生意気になってきたんじゃないか？","ENG":"Well, look who's a big girl now? That's no way to treat someone who put up with all your nonsense!","TWN":"嘖嘖～你翅膀硬啦！你每次吹牛我都沒說你，你還敢說我？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"헤드락 풀어! 땀 냄새 난다니까, 진짜!","JPN":"ちょっと！　放してよ！　汗臭いんだよ！　もう！","ENG":"Release this headlock! You smell bad!","TWN":"哎唷～放開我啦！都是汗臭味，好臭！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아? 잠깐! 호라이즌!","JPN":"あっ、待って！　ホライズン！","ENG":"Huh? Wait! Horizon!","TWN":"喂！地平線，等一下！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"무슨 일입니까, 휴먼.","JPN":"どうしましたか、ヒューマン。","ENG":"What is it, human?","TWN":"什麼事嗎？人類。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"소음 공해 요인은 모두 정리되었으니 저도 돌아가야죠.","JPN":"騒音公害の要因はすべて処理したので、私も戻ります。","ENG":"I must return now that the source of the noise has been dealt with.","TWN":"噪音污染的來源已經全都清除完畢，那我也該回去了。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"먼지를 잔뜩 뒤집어썼잖아.","JPN":"埃まみれじゃない。","ENG":"You're covered in dust.","TWN":"你看你身上都是灰塵！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"보육원으로 가자. 내가 씻겨 줄게.","JPN":"孤児院に戻ろう。お風呂で流してあげる。","ENG":"Come to the orphanage with me. I'll help you wash up.","TWN":"跟我回去育幼院，我幫你清理一下！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"자기 세척도 못할 만큼 성능이 떨어지진 않습니다만.","JPN":"自己洗浄もできないほど性能は衰えていませんが。","ENG":"I'm not so indisposed that I cannot even clean myself.","TWN":"我的性能還沒有差到無法自我清理。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"으휴, 하여튼 언니가 뭐라고 하면 네, 하는 법이 없어요.","JPN":"はあ、お姉ちゃんに誘われたら素直に「はい」って言ってよね。","ENG":"Ugh, can't you just say yes for a change?","TWN":"真是的，不管姊姊我說什麼，你就是不能乖乖說好！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그러니까…… 어제 화내서 미안해. 사과의 의미로 뭐라도 대접해 줄게.","JPN":"だから、その……昨日は怒ってごめんね。お詫びとして何かおごってあげるから。","ENG":"The thing is… I'm sorry I got mad at you yesterday. So let me make it up to you somehow.","TWN":"那個……昨天那樣兇你，對不起。就讓我為你做點事當作是道歉吧。 "},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"그리고 말이야!","JPN":"あとね！","ENG":"And also!","TWN":"還有！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"소음을 일으킨 건 우리한테도 책임이 있으니까, 빚 갚는 셈 치고. 응?","JPN":"騒音はアタシたちにも責任があるから、借りを返すってことで、いいよね？","ENG":"We're partly to blame for the noise, so consider us even after this. How about it?","TWN":"造成噪音的部分我們也有責任，就當我們欠你的好嗎？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"……그 말은, 변제하겠다는 뜻입니까?","JPN":"……それはつまり、返済するという意味ですか？","ENG":"…You mean you'll make reparations?","TWN":"……意思是，要還債的意思是嗎？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"어? 으, 응. 뭐 비슷한 의미려나?","JPN":"え？　あ、うん。まあ似たような意味じゃない？","ENG":"Huh? S-sure. Something like that.","TWN":"蛤？喔，差不多意思吧？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"그런 의도라면 거절하지 않겠습니다.","JPN":"……でしたら、受け入れましょう。","ENG":"If that is the intent, I will not decline.","TWN":"如果是要還債，那我不會拒絕。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"정말? 너 그러다가 또 말 바꾸는 거 아니지?","JPN":"本当に？　あとで嫌だとか言わないでね！","ENG":"Really? You're not gonna change your mind halfway, are you?","TWN":"真的？你不會中途又反悔吧？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 한 번 한 말은 반드시 지킵니다. 신용은 금융업에서 생명이나 마찬가지니까요.","JPN":"私は一度言ったことは必ず守ります。金融業では信用が命ですので。","ENG":"I always keep my word. Credibility is a vital virtue in the finance industry.","TWN":"我說話算話，因為在金融界信用就跟性命一樣重要。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"좋아! 내가 식당 아줌마한테 우리 보육원에서 제일 맛있는 식단으로 달라고 해 줄게!","JPN":"よし！　食堂のおばさんにうちの孤児院で一番おいしいメニューを頼んでおくから！","ENG":"Great! I'll ask the cafeteria lady to prepare the best food the orphanage has to offer!","TWN":"非常好！那我請廚房阿姨端出育幼院裡最棒的菜色！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HORIZON_HORIZON_NULL_NULL","text":{"KOREA":"저는 윤활유면 충분합니다.","JPN":"私は潤滑油があれば十分です。","ENG":"A can of lubricant will be sufficient for me.","TWN":"給我潤滑油就好。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"이럴 때에도 자기 설정에 충실하구나, 너…….","JPN":"こういう時もその設定を守るんだね……","ENG":"Wow, you're really committed to your thing, aren't you…","TWN":"這種時候你還是非常忠於你的人設呢……"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"HORIZON_HORIZON_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"왜 그러십니까, 교관님? 쟤들이 입에 돈다발이라도 물고 다니는 것처럼?","JPN":"どうしたんですか、教官？　あの子たちが心配ですか？","ENG":"What's wrong, Instructor? You're staring at them as if your eyes were stuck open.","TWN":"教官，你怎麼了？怎麼一臉失神？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"놈들이 레이첼에게 로켓탄을 쏠 때는 아찔했어. 내 판단 미스로 또 아까운 목숨을 잃는 줄 알았으니까.","JPN":"やつらがレイチェルにロケット弾を撃った時はヒヤッとした。\\n俺の判断ミスでまた誰かの命が失われると思ったからな。","ENG":"It was harrowing when they shot that rocket at Rachel. I thought my poor judgment had cost another life.","TWN":"那些傢伙朝瑞秋發射砲彈時，我的心臟都要停了。我以為會因為我的判斷錯誤，又要失去一條寶貴的生命。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"이봐, 멀쩡하게 날아가던 로켓탄이 갑자기 직각으로 꺾일 확률이 얼마나 된다고 생각하지?","JPN":"なあ、普通に飛んでいたロケット弾が急に直角に曲がる確率はどれくらいあると思う？","ENG":"Tell me something. What do you think the odds are for a perfectly fine rocket suddenly changing its course 90 degrees?","TWN":"你認為，準確發射出來的砲彈，要突然轉彎的機率有多高？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"글쎄요……. 진짜 더럽게 운이 좋다고 밖에는 못하겠죠.","JPN":"さあ……とんでもなく運がよかったとしか言いようがないですね。","ENG":"I don't know… All I can say is Lady Luck must have been in one hell of a good mood today.","TWN":"這個嘛……只能說是走狗屎運吧？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"아마 지하철도에 숨어 있는 동안 부품이 녹슨 줄도 몰랐던 거 아닐까요?","JPN":"おそらく地下鉄に潜んでいる間、部品が錆びてしまったことに気づかなかったのではないでしょうか？","ENG":"Maybe their gear got rusty while sitting in the subway?","TWN":"或是他們不知道藏在地鐵的時候，有零件生鏽吧？"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"……그래. 그 편이 훨씬 받아들이기 쉽겠군.","JPN":"……そうだな。そう思った方がいいかもしれない。","ENG":"Sure… I guess that's an easier explanation to digest.","TWN":"……嗯嗯，這種說法比較合理。"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L27_1","type":"dialog","speaker":"SEONGTAE_MILITIA_NULL_NULL","text":{"KOREA":"출발하지. 이 근방에서 배회하는 침식체들을 피하려면 해 떨어지기 전에는 돌아와야 할 테니까.","JPN":"出発しよう。この辺でうろついている侵食体を避けるためには、日が沈む前に戻らないと。","ENG":"Let's get going then. We'll have to get back before sunset if we want to avoid the C.O.s around here.","TWN":" "},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEONGTAE_MILITIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MEMBER_NPC_MILITIA_NULL","text":{"KOREA":"알겠습니다, 교관님!","JPN":"わかりました、教官！","ENG":"Understood, Instructor!","TWN":"是，教官！"},"stage":{"bg":"HIGHWAY_TWILIGHT","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MEMBER_NPC_MILITIA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};